import { lazy, Suspense } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { tokens } from '../styles/tokens'

const PublicNav = lazy(() => import('@/components/PublicNav'))
const PublicFooter = lazy(() => import('@/components/PublicFooter'))

const T = {
  bg: tokens.color.bg,
  surface: tokens.color.surface,
  border: tokens.color.border,
  textPrimary: tokens.color.text,
  textSecondary: tokens.color.textSecondary,
  blue: tokens.color.blue,
  purple: tokens.color.purple,
  monoFont: tokens.font.mono,
  bodyFont: tokens.font.sans,
}

export default function NotFoundPage() {
  const navigate = useNavigate()
  const token = typeof window !== 'undefined' ? localStorage.getItem('aura_token') : null
  const isPublic = !token

  return (
    <div style={{
      minHeight: '100vh', display: 'flex', flexDirection: 'column',
      background: T.bg, fontFamily: T.bodyFont,
    }}>
      {isPublic && (
        <Suspense fallback={null}>
          <PublicNav />
        </Suspense>
      )}

      <div style={{
        flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center',
        justifyContent: 'center', padding: 32, position: 'relative',
      }}>
        {/* Subtle glow */}
        <div style={{
          position: 'absolute', width: 400, height: 400, borderRadius: '50%',
          background: `radial-gradient(circle, ${T.blue}08, transparent 70%)`,
          pointerEvents: 'none',
        }} />

        {/* 404 number */}
        <div style={{
          fontSize: 120, fontWeight: 800, fontFamily: T.monoFont,
          background: `linear-gradient(135deg, ${T.blue}, ${T.purple})`,
          WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
          backgroundClip: 'text', lineHeight: 1, marginBottom: 16,
          position: 'relative',
        }}>
          404
        </div>

        {/* Message */}
        <h1 style={{
          fontSize: 24, fontWeight: 700, color: T.textPrimary,
          margin: '0 0 8px', textAlign: 'center',
        }}>
          Page not found
        </h1>
        <p style={{
          fontSize: 15, color: T.textSecondary, textAlign: 'center',
          maxWidth: 400, lineHeight: 1.6, margin: '0 0 32px',
        }}>
          The page you're looking for doesn't exist or has been moved.
        </p>

        {/* Buttons */}
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', justifyContent: 'center' }}>
          <Link to={token ? '/home' : '/landing'} style={{
            display: 'inline-flex', alignItems: 'center', gap: 8,
            padding: '12px 28px', borderRadius: 10,
            background: `linear-gradient(135deg, ${T.blue}, ${T.purple})`,
            color: '#fff', fontSize: 14, fontWeight: 600,
            textDecoration: 'none', transition: 'opacity 0.15s ease',
            boxShadow: `0 4px 16px ${T.blue}33`,
          }}
            onMouseEnter={e => { e.currentTarget.style.opacity = '0.85' }}
            onMouseLeave={e => { e.currentTarget.style.opacity = '1' }}
          >
            {token ? 'Go to Dashboard' : 'Go Home'}
          </Link>
          <Link to={token ? '/strategies' : '/strategies-public'} style={{
            display: 'inline-flex', alignItems: 'center', gap: 8,
            padding: '12px 28px', borderRadius: 10,
            background: 'transparent',
            color: T.textPrimary, fontSize: 14, fontWeight: 600,
            textDecoration: 'none', transition: 'opacity 0.15s ease',
            border: `1px solid ${T.border}`,
          }}
            onMouseEnter={e => { e.currentTarget.style.opacity = '0.7' }}
            onMouseLeave={e => { e.currentTarget.style.opacity = '1' }}
          >
            Browse Strategies
          </Link>
          <button
            onClick={() => navigate(-1)}
            style={{
              display: 'inline-flex', alignItems: 'center', gap: 8,
              padding: '12px 28px', borderRadius: 10,
              background: 'transparent', cursor: 'pointer',
              color: T.textSecondary, fontSize: 14, fontWeight: 600,
              border: `1px solid ${T.border}`,
              transition: 'opacity 0.15s ease',
            }}
            onMouseEnter={e => { e.currentTarget.style.opacity = '0.7' }}
            onMouseLeave={e => { e.currentTarget.style.opacity = '1' }}
          >
            Go Back
          </button>
        </div>
      </div>

      {isPublic && (
        <Suspense fallback={null}>
          <PublicFooter />
        </Suspense>
      )}
    </div>
  )
}
